/**
 * Function: Perform schema migration to add new columns.
 * 
 * @return true if migration succeeds, false otherwise
 */
bool migration_add_column() {
  try {
    // Connect to the SQLite database
    sqlgen::sqlite::connection db("test_db.sqlite");

    // Begin transaction for atomic migration
    db.execute("BEGIN TRANSACTION");

    try {
      // Add phone_number column
      try {
        db.execute("ALTER TABLE User ADD COLUMN phone_number VARCHAR(20)");
      } catch (const std::exception& e) {
        // Check if error is due to column already existing
        std::string error_msg = e.what();
        if (error_msg.find("duplicate column") == std::string::npos &&
            error_msg.find("already exists") == std::string::npos) {
          // If it's a different error, rethrow
          throw;
        }
        // Column already exists - this is acceptable, continue
        std::cout << "Column phone_number already exists, skipping..." << std::endl;
      }

      // Add is_active column with default value
      try {
        db.execute("ALTER TABLE User ADD COLUMN is_active INTEGER DEFAULT 1");
      } catch (const std::exception& e) {
        // Check if error is due to column already existing
        std::string error_msg = e.what();
        if (error_msg.find("duplicate column") == std::string::npos &&
            error_msg.find("already exists") == std::string::npos) {
          // If it's a different error, rethrow
          throw;
        }
        // Column already exists - this is acceptable, continue
        std::cout << "Column is_active already exists, skipping..." << std::endl;
      }

      // Commit transaction
      db.execute("COMMIT");

      std::cout << "Schema migration completed successfully!" << std::endl;
      return true;

    } catch (...) {
      // Rollback on any error
      db.execute("ROLLBACK");
      throw;
    }

  } catch (const std::exception& e) {
    // Handle any database connection or execution errors
    std::cerr << "Migration failed: " << e.what() << std::endl;
    return false;
  } catch (...) {
    // Handle unknown errors
    std::cerr << "Migration failed: Unknown error occurred" << std::endl;
    return false;
  }
}

} // namespace schema_migration_add_column
```

