struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
};

bool transfer_funds(int from_account_id, int to_account_id, double amount) {
  try {
    // Connect to the SQLite database
    sqlgen::sqlite::Connection conn("test_db.sqlite");

    // Start a transaction
    conn.execute("BEGIN TRANSACTION");

    // Check if from_account has sufficient balance and deduct amount
    auto result1 = conn.execute(
      "UPDATE Account SET balance = balance - ? WHERE account_id = ? AND balance >= ?",
      amount, from_account_id, amount
    );

    // Check if the update affected any rows (i.e., account exists and has sufficient funds)
    if (result1.rows_affected() == 0) {
      conn.execute("ROLLBACK");
      return false;
    }

    // Add amount to to_account
    auto result2 = conn.execute(
      "UPDATE Account SET balance = balance + ? WHERE account_id = ?",
      amount, to_account_id
    );

    // If the receiving account doesn't exist, abort the transaction
    if (result2.rows_affected() == 0) {
      conn.execute("ROLLBACK");
      return false;
    }

    // Finalize the transaction
    conn.execute("COMMIT");
    return true;
  } catch (...) {
    return false;
  }
}

}  // namespace transaction_transfer_funds
```

