#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace right_join_departments_projects {

struct Department {
  sqlgen::PrimaryKey<int> department_id;
  std::string name;
};

struct Project {
  sqlgen::PrimaryKey<int> project_id;
  int department_id;
  std::string name;
};

struct DepProj {
  std::optional<std::string> department_name;
  std::string project_name;
};

/**
 * description: right_join_departments_projects.
 * This function demonstrates how to perform a right join between departments and projects using sqlgen read API.
 * It returns a vector of DepProj structs, where each struct contains the department name (if available) and the project name.
 * Returns: std::vector<DepProj>.
 */
std::vector<DepProj> right_join_departments_projects() {
  // Connect to SQLite database
  auto db = sqlgen::sqlite::open("test_db.sqlite");

  std::vector<DepProj> results;

  // SQLite doesn't support RIGHT JOIN directly, so we use LEFT JOIN with reversed order
  // Department RIGHT JOIN Project is equivalent to Project LEFT JOIN Department
  // This ensures all projects are included, with optional department information
  auto query = db.query(
    "SELECT d.name AS department_name, p.name AS project_name "
    "FROM Project p "
    "LEFT JOIN Department d ON p.department_id = d.department_id"
  );

  // Execute query and process results
  for (auto& row : query) {
    DepProj dp;

    // Department name may be NULL if project has no associated department
    if (!row["department_name"].is_null()) {
      dp.department_name = row["department_name"].as<std::string>();
    }

    // Project name is always present
    dp.project_name = row["project_name"].as<std::string>();

    results.push_back(dp);
  }

  return results;
}

}  // namespace right_join_departments_projects
```

**Key Implementation Notes:**

1. **SQLite RIGHT JOIN Limitation**: SQLite doesn't support RIGHT JOIN syntax, so the query uses `Project LEFT JOIN Department` which is equivalent to `Department RIGHT JOIN Project`.

2. **Join Logic**: The join includes all projects (ensuring `project_name` is always populated) and optionally includes department information when available.

3. **Optional Handling**: The `department_name` field uses `std::optional` to handle cases where a project has no associated department (NULL values).

4. **Database Connection**: Opens the SQLite database file "test_db.sqlite" using the sqlgen library.

5. **Result Mapping**: Iterates through query results and maps each row to a `DepProj` struct with appropriate NULL handling.

